namespace BlazorNotifications.Services;

public record Notification(int Id, string Message, DateTime Timestamp);

public class NotificationService
{
    private int _nextId = 1;
    private readonly List<Notification> _notifications = new();
    private readonly Lock _lock = new();

    public NotificationService()
    {
        // Seed with initial fake data.
        _notifications.Add(new(NextId(), "Welcome to the notification center!", DateTime.UtcNow.AddMinutes(-10)));
        _notifications.Add(new(NextId(), "Your profile was updated successfully.", DateTime.UtcNow.AddMinutes(-5)));
        _notifications.Add(new(NextId(), "New comment on your post.", DateTime.UtcNow.AddMinutes(-2)));
    }

    /// <summary>Returns all notifications.</summary>
    public List<Notification> GetAll()
    {
        lock (_lock)
        {
            return [.. _notifications];
        }
    }

    /// <summary>Returns only notifications newer than the given id.</summary>
    public List<Notification> GetNewerThan(int lastSeenId)
    {
        lock (_lock)
        {
            return _notifications.Where(n => n.Id > lastSeenId).ToList();
        }
    }

    /// <summary>Simulates a new notification arriving at random intervals.</summary>
    public void SimulateIncoming()
    {
        // ~30 % chance each poll cycle to add a new notification.
        if (Random.Shared.Next(100) < 30)
        {
            lock (_lock)
            {
                _notifications.Add(new(NextId(),
                    $"New event at {DateTime.UtcNow:T} — item #{_notifications.Count + 1}",
                    DateTime.UtcNow));
            }
        }
    }

    private int NextId() => _nextId++;
}

@page "/notifications"
@rendermode @(new InteractiveServerRenderMode(prerender: true))
@implements IDisposable
@inject BlazorNotifications.Services.NotificationService NotificationService

<PageTitle>Notifications</PageTitle>

<h2>
    Notifications
    <span class="badge bg-primary rounded-pill ms-2">@notifications.Count</span>
</h2>

@if (notifications.Count == 0)
{
    <p><em>No notifications yet.</em></p>
}
else
{
    <ul class="list-group mt-3">
        @foreach (var n in notifications.OrderByDescending(x => x.Timestamp))
        {
            <li class="list-group-item d-flex justify-content-between align-items-start">
                <span>@n.Message</span>
                <small class="text-muted">@n.Timestamp.ToString("HH:mm:ss")</small>
            </li>
        }
    </ul>
}

@code {
    private List<BlazorNotifications.Services.Notification> notifications = new();
    private CancellationTokenSource? _cts;
    private int _lastSeenId;

    // Runs during prerender AND on interactive connect — but we gate the poll.
    protected override void OnInitialized()
    {
        // Load initial data (appears in server-rendered HTML).
        notifications = NotificationService.GetAll();
        _lastSeenId = notifications.Count > 0 ? notifications.Max(n => n.Id) : 0;
    }

    protected override void OnAfterRender(bool firstRender)
    {
        if (firstRender)
        {
            // OnAfterRender only fires on the interactive runtime, never during
            // static/prerender, so this is the safe place to start the poll loop.
            _cts = new CancellationTokenSource();
            _ = PollForNotificationsAsync(_cts.Token);
        }
    }

    private async Task PollForNotificationsAsync(CancellationToken ct)
    {
        while (!ct.IsCancellationRequested)
        {
            await Task.Delay(5_000, ct).ConfigureAwait(false);

            // Simulate new notifications being generated server-side.
            NotificationService.SimulateIncoming();

            var newer = NotificationService.GetNewerThan(_lastSeenId);
            if (newer.Count > 0)
            {
                _lastSeenId = newer.Max(n => n.Id);
                await InvokeAsync(() =>
                {
                    notifications.AddRange(newer);
                    StateHasChanged();
                });
            }
        }
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

